interface ExpansionItem {
  id: string;
  label: string;
  sub: string;
  locked?: boolean;
  isSubItem?: boolean;
  isGiant?: boolean;
  subItems?: ExpansionItem[];
}

interface ExpansionGroup {
  category: string;
  items: ExpansionItem[];
}

interface Card {
  id: string;
  index: number;
  name: string;
  cardNumber: string;
  rarity: string;
  type: string;
  color: string;
  expansion: string;
  imageUrl: string;
  backImageUrl?: string;
  isFoil?: boolean;
  legalStatus?: 'Banned' | 'Limited' | 'Errata' | 'Banned (BO1)';
  legalDate?: string;
  sourceProduct?: string;
  releaseDate?: string;
  description?: string;
  sourceUrl?: string;
  traits?: string;
  skill?: string;
  power?: string;
  energy?: string;
  comboEnergy?: string;
  comboPower?: string;
  character?: string;
  era?: string;
  specialTrait?: string;
  backPower?: string;
  backCharacter?: string;
  backEra?: string;
  backSpecialTrait?: string;
  backSkill?: string;
}

interface InventoryItem {
  id: string;
  cardId: string;
  quantity: number;
  ownerId: string;
  addedAt?: any;
}

interface WantsList {
  id: string;
  ownerId: string | null;
  name: string;
  description?: string;
  cardIds: string[];
  acquiredCardIds: string[];
  cardQuantities?: Record<string, number>;
  acquiredQuantities?: Record<string, number>;
  isPublic?: boolean;
  gameType?: 'masters' | 'fusion' | string;
  createdAt?: any;
  updatedAt?: any;
}

interface UserAchievement {
  id: string;
  achievementId: string;
  ownerId: string;
  unlockedAt: any;
  currentProgress?: number;
  currentTier?: number;
  isSeen?: boolean;
}

interface AchievementDef {
  id: string;
  title: Record<'es' | 'en', string>;
  description: Record<'es' | 'en', string>;
  icon: string;
  type: 'unique' | 'tiered';
  category: string;
  subCategory?: string;
  hidden?: boolean;
  tiers?: { goal: number; title: Record<'es' | 'en', string> }[];
  check: (cards: Card[], inventory: InventoryItem[]) => { earned: boolean; progress?: number; tier?: number };
}

