const renderEnergyCost = (energy: string) => {
  if (!energy) return null;
  const match = energy.match(/^(\d+|-)(?:\(([A-Z]+)\))?$/);
  
  if (match) {
    const total = match[1];
    const colors = match[2] || '';
    
    return (
      <span className="flex items-center text-[11px] font-bold text-white leading-none">
        {total !== '-' && <span className="mr-1">{total}</span>}
        {colors.split('').map((c, i) => {
           let dotBg = "bg-gray-400";
           if (c === 'R') dotBg = "bg-[#E62020] border border-[#FF6B6B]";
           else if (c === 'B' || c === 'U') dotBg = "bg-[#0A5BC4] border border-[#4D94FF]";
           else if (c === 'G') dotBg = "bg-[#1C8A33] border border-[#40CC5E]";
           else if (c === 'Y') dotBg = "bg-[#D9A100] border border-[#FFCF3D]";
           else if (c === 'K' || c === 'W') {
             // Handle K and W similar to before, K is black, W is white
             dotBg = c === 'K' ? "bg-zinc-800 border border-zinc-500/50" : "bg-white border border-gray-300";
           }
           
           return (
             <span key={i} className={`inline-flex items-center justify-center w-3 h-3 rounded-full ${dotBg} shadow-[0_1px_2px_rgba(0,0,0,0.5)] mr-0.5`} title={c} />
           );
        })}
      </span>
    );
  }
  
  return <span className="font-bold text-white text-[10px]">{energy}</span>;
};

const renderSkillText = (text: string) => {
  const parts = text.split(/(\[.*?\])/g);
  return parts.map((part, index) => {
    if (part.startsWith('[') && part.endsWith(']')) {
      const content = part.slice(1, -1);
      const lower = content.toLowerCase();
      
      // Check if it is a colorless energy cost like [one], [two], [1], [2], etc.
      const numMap: { [key: string]: string } = {
        one: '1', two: '2', three: '3', four: '4', five: '5',
        six: '6', seven: '7', eight: '8', nine: '9', ten: '10',
        free: '0', zero: '0'
      };
      
      if (numMap[lower] !== undefined || /^\d+$/.test(lower)) {
        const val = numMap[lower] || lower;
        return (
          <span key={index} className="inline-flex items-center justify-center w-3.5 h-3.5 rounded-full bg-white border border-gray-400 text-black text-[9px] font-black shadow-[0_1px_2px_rgba(0,0,0,0.4)] mx-0.5 align-middle select-none" style={{ transform: 'translateY(-1px)' }}>
            {val}
          </span>
        );
      }
      
      let bgClass = "bg-red-600 border border-red-500 text-white";
      let txtClass = "text-white";
      
      if (lower.includes('auto')) {
        bgClass = "bg-[#0A417C] border border-[#1E67C1]";
      } else if (lower.includes('activate') || lower.includes('awaken') || lower.includes('wish')) {
        bgClass = "bg-[#D9A100] border border-[#FFCF3D]";
        txtClass = "text-black drop-shadow-[0_1px_0_rgba(255,255,255,0.4)]";
      } else if (lower.includes('counter')) {
        bgClass = "bg-[#1E7C1E] border border-[#2DB82D]";
      }
      
      return (
        <span key={index} className={`inline-block px-1.5 py-0.5 rounded text-[10px] font-black mr-1 uppercase tracking-wider align-middle shadow-sm leading-none bg-opacity-90 ${bgClass} ${txtClass}`}>
          {content}
        </span>
      );
    }
    
    // Split by curly brace segments (e.g. {R}) or by uppercase color-cost boundaries (e.g. RRR, BB, G, Y, K, W) or word boundary/Japanese costs
    const textParts = part.split(/((?:\{[a-zA-Z0-9]+\})+\s*\d*|\b[RBYGKW]+\b|[白赤青緑黄黒紫])/g);
    
    return (
      <span key={index} className="align-middle inline-block">
        {textParts.map((tPart, j) => {
            if (/^(?:\{[a-zA-Z0-9]+\})+\s*\d*$/.test(tPart)) {
              const marks = [...tPart.matchAll(/\{([a-zA-Z0-9]+)\}/g)];
              const trailingNumMatch = tPart.match(/\}\s*(\d+)$/);
              const trailingNum = trailingNumMatch ? trailingNumMatch[1] : null;
              
              const allValid = marks.length > 0 && marks.every(m => {
                const colorChar = m[1].toUpperCase();
                const validColors = ['R', 'B', 'U', 'G', 'Y', 'K', 'BK', 'W', 'WHITE', 'BLACK'];
                return validColors.includes(colorChar) || /^\d+$/.test(colorChar);
              });

              if (allValid) {
                return (
                  <span key={j} className="inline-flex items-center align-middle mx-1" style={{ transform: 'translateY(-1px)' }}>
                    {marks.map((m, k) => {
                      const colorChar = m[1].toUpperCase();
                      let dotBg = "bg-gray-400";
                      let innerText = "";
                      
                      if (colorChar === 'R') dotBg = "bg-[#E62020] border border-[#FF6B6B]";
                      else if (colorChar === 'B' || colorChar === 'U') dotBg = "bg-[#0A5BC4] border border-[#4D94FF]";
                      else if (colorChar === 'G') dotBg = "bg-[#1C8A33] border border-[#40CC5E]";
                      else if (colorChar === 'Y') dotBg = "bg-[#D9A100] border border-[#FFCF3D]";
                      else if (colorChar === 'K' || colorChar === 'BK' || colorChar === 'BLACK') dotBg = "bg-zinc-800 border border-zinc-500/50";
                      else if (colorChar === 'W' || colorChar === 'WHITE') dotBg = "bg-white border border-gray-300";
                      else if (/^\d+$/.test(colorChar)) {
                        dotBg = "bg-white border border-gray-300";
                        innerText = colorChar;
                      }
                      
                      return (
                        <span key={k} className={`inline-flex items-center justify-center w-3.5 h-3.5 rounded-full ${dotBg} shadow-[0_1px_2px_rgba(0,0,0,0.5)] mr-0.5`} title={colorChar}>
                          {innerText && <span className="text-black text-[9px] font-black leading-none">{innerText}</span>}
                        </span>
                      );
                    })}
                    {trailingNum && (
                      <span className="inline-flex items-center justify-center w-3.5 h-3.5 rounded-full bg-white border border-gray-300 text-black text-[9px] font-black shadow-[0_1px_2px_rgba(0,0,0,0.5)] mr-0.5" style={{ lineHeight: 1 }}>
                        {trailingNum}
                      </span>
                    )}
                  </span>
                );
              }
            } else if (/^[RBYGKW]+$/.test(tPart) || /^[白赤青緑黄黒紫]$/.test(tPart)) {
              return (
                <span key={j} className="inline-flex items-center align-middle mx-1" style={{ transform: 'translateY(-1px)' }}>
                  {tPart.split('').map((colorChar, k) => {
                    let dotBg = "bg-gray-400";
                    if (colorChar === 'R' || colorChar === '赤') dotBg = "bg-[#E62020] border border-[#FF6B6B]";
                    else if (colorChar === 'B' || colorChar === '青') dotBg = "bg-[#0A5BC4] border border-[#4D94FF]";
                    else if (colorChar === 'G' || colorChar === '緑') dotBg = "bg-[#1C8A33] border border-[#40CC5E]";
                    else if (colorChar === 'Y' || colorChar === '黄') dotBg = "bg-[#D9A100] border border-[#FFCF3D]";
                    else if (colorChar === 'K' || colorChar === '黒') dotBg = "bg-zinc-800 border border-zinc-500/50";
                    else if (colorChar === 'W' || colorChar === '白') dotBg = "bg-white border border-gray-300";
                    
                    return (
                      <span key={k} className={`inline-flex items-center justify-center w-3.5 h-3.5 rounded-full ${dotBg} shadow-[0_1px_2px_rgba(0,0,0,0.4)] mr-0.5 select-none`} title={colorChar} />
                    );
                  })}
                </span>
              );
            }
            return <span key={j}>{tPart}</span>;
        })}
      </span>
    );
  });
};

