      description: { es: 'Completa el playset (4 copias) de BT13-088, BT13-085, BT13-087 y BT13-086.', en: 'Complete the playset (4 copies) of BT13-088, BT13-085, BT13-087 and BT13-086.' },
      type: 'unique',
