            'FB06-113_A_SB01': 'FB06-113_p1', 'FB06-113_B_SB01': 'FB06-113_p2', 'FB06-117_A_SB01': 'FB06-117_p1',
            'FS05-05_A_SB01': 'FS05-05_p2',
            // SB02 Mappings
            'FB01-107_A_SB02': 'FB01-107_p2', 'FB01-108_A_SB02': 'FB01-108_p3', 'FB01-108_B_SB02': 'FB01-108_p4',
