              const p_suffix = mapped.split('_')[1];
              imageUrl = `https://www.dbs-cardgame.com/fw/images/cards/card/en/${base}_f_${p_suffix}.webp`;
              backImageUrl = `https://www.dbs-cardgame.com/fw/images/cards/card/en/${base}_b_${p_suffix}.webp`;
